import type { Option } from '@/pdp/data/models';

/** Single-select option group (one chosen item UID). */
export type ProductOptionSelectionSingle = { label: string; value: string };

/** Multi-select option group (one or more chosen item UIDs). */
export type ProductOptionSelectionMulti = { label: string; values: string[] };

export type ProductOptionSelectionEntry =
  | ProductOptionSelectionSingle
  | ProductOptionSelectionMulti;

export type ProductOptionSelectionMap = {
  [optionId: string]: ProductOptionSelectionEntry;
};

/**
 * Flatten selection map to UID list. When `optionsOrder` is provided (e.g. `data.options`),
 * UIDs are emitted in that order for stable URLs and API payloads.
 */
export function selectionMapToOptionUIDs(
  selections: ProductOptionSelectionMap,
  optionsOrder?: Option[]
): string[] {
  if (!optionsOrder?.length) {
    return Object.values(selections).flatMap((entry) =>
      'values' in entry ? entry.values : entry.value ? [entry.value] : []
    );
  }

  const list: string[] = [];
  for (const def of optionsOrder) {
    const entry = selections[def.id];
    if (!entry) continue;
    if ('values' in entry) {
      const order = new Map(def.items.map((item, idx) => [item.id, idx]));
      const sorted = [...entry.values].sort(
        (a, b) => (order.get(a) ?? 0) - (order.get(b) ?? 0)
      );
      list.push(...sorted);
    } else if ('value' in entry && entry.value) {
      list.push(entry.value);
    }
  }
  return list;
}

/**
 * Whether the shopper has satisfied all option groups for add-to-cart.
 * Bundle multi-select may contribute more than one UID while still satisfying one group.
 */
export function isProductOptionsSelectionComplete(
  options: Option[] | undefined,
  optionUIDs: string[] | undefined,
  isBundle: boolean | undefined
): boolean {
  if (!options?.length) {
    return true;
  }

  const uids = optionUIDs ?? [];

  if (isBundle) {
    return options.every((option) => {
      if (!option.required) {
        return true;
      }
      const selectedCount = option.items.filter((item) =>
        uids.includes(item.id)
      ).length;
      return selectedCount >= 1;
    });
  }

  return uids.length === options.length;
}
